__kernel void BFS_1(
    const int* d_graph_nodes_starting,
    const int* d_graph_nodes_no_of_edges,
    const int* d_graph_edges,
    char* d_graph_mask,
    char* d_updating_graph_mask,
    const char* d_graph_visited,
    int* d_cost,
    int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid >= no_of_nodes) return;

    if (d_graph_mask[tid] == 1) {
        d_graph_mask[tid] = 0;
        int start = d_graph_nodes_starting[tid];
        int end = start + d_graph_nodes_no_of_edges[tid];
        int current_cost = d_cost[tid];

        for (int i = start; i < end; i++) {
            int id = d_graph_edges[i];
            if (d_graph_visited[id] == 0) {
                d_cost[id] = current_cost + 1;
                d_updating_graph_mask[id] = 1;
            }
        }
    }
}

__kernel void BFS_2(
    char* d_graph_mask,
    char* d_updating_graph_mask,
    char* d_graph_visited,
    char* d_over,
    int no_of_nodes)
{
    int tid = get_global_id(0);
    if (tid >= no_of_nodes) return;

    if (d_updating_graph_mask[tid] == 1) {
        d_graph_mask[tid] = 1;
        d_graph_visited[tid] = 1;
        *d_over = 1;
        d_updating_graph_mask[tid] = 0;
    }
}
